import * as admin from "firebase-admin";
import * as functions from "firebase-functions";
import * as path from "path";

admin.initializeApp();

// Store the Next.js request handler
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let nextHandler: any = null;
let initPromise: Promise<void> | null = null;

/**
 * Initialize Next.js server from standalone build
 */
async function initializeNextServer() {
  if (nextHandler) {
    return;
  }

  if (initPromise) {
    await initPromise;
    return;
  }

  initPromise = (async () => {
    try {
      // Load the standalone server.js
      const serverPath = path.join(__dirname, "..", ".next-standalone", "server.js");
      // eslint-disable-next-line global-require
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      const {default: server} = require(serverPath);
      nextHandler = server;
      console.log("Next.js server initialized");
    } catch (error) {
      console.error("Failed to initialize Next.js server:", error);
      throw error;
    }
  })();

  await initPromise;
}

/**
 * Cloud Function that serves the Next.js app
 */
export const nextApp = functions.https.onRequest(async (req, res) => {
  try {
    // Initialize on first request
    if (!nextHandler) {
      await initializeNextServer();
    }

    if (!nextHandler) {
      res.status(503).json({error: "Service unavailable"});
      return;
    }

    // Forward request to Next.js server
    nextHandler(req, res);
  } catch (error) {
    console.error("Error serving Next.js:", error);
    res.status(500).json({error: "Internal server error"});
  }
});

import * as admin from "firebase-admin";
import * as functions from "firebase-functions";
import * as path from "path";

admin.initializeApp();

// Store the Next.js request handler
// eslint-disable-next-line @typescript-eslint/no-explicit-any
let nextHandler: any = null;
let initPromise: Promise<void> | null = null;

/**
 * Initialize Next.js server from standalone build
 */
async function initializeNextServer() {
  if (nextHandler) {
    return;
  }

  if (initPromise) {
    await initPromise;
    return;
  }

  initPromise = (async () => {
    try {
      // Load the standalone server.js
      const serverPath = path.join(
        __dirname,
        "..",
        ".next-standalone",
        "server.js",
      );
      // eslint-disable-next-line global-require
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      const {default: server} = require(serverPath);
      nextHandler = server;
      console.log("Next.js server initialized");
    } catch (error) {
      console.error("Failed to initialize Next.js server:", error);
      throw error;
    }
  })();

  await initPromise;
}

/**
 * Cloud Function that serves the Next.js app
 */
export const nextApp = functions.https.onRequest(async (req, res) => {
  try {
    // Initialize on first request
    if (!nextHandler) {
      await initializeNextServer();
    }

    if (!nextHandler) {
      res.status(503).json({error: "Service unavailable"});
      return;
    }

    // Forward request to Next.js server
    nextHandler(req, res);
  } catch (error) {
    console.error("Error serving Next.js:", error);
    res.status(500).json({error: "Internal server error"});
  }
});
